import {
  BrowserRouter,
  Routes,
  Route
} from 'react-router-dom'

import PrintHome from './pages/PrintHome'
import CategoryPage from './pages/CategoryPage'

function App() {

  return (

    <BrowserRouter>

      <Routes>

        <Route
          path="/"
          element={<PrintHome />}
        />

        <Route
          path="/print"
          element={<PrintHome />}
        />

        <Route
          path="/print/:category"
          element={<CategoryPage />}
        />

      </Routes>

    </BrowserRouter>

  )
}

export default App
